questions.question:
分析以下代码的错误并改正：
FILE *fp;
fp = fopen("test.txt", "r");
fprintf(fp, "Hello");
fclose(fp);

questions.answer:
错误：以只读模式"r"打开文件后尝试写入，会导致写入失败。
改正：将模式改为"w"或"a"等可写模式。
正确代码：
FILE *fp;
fp = fopen("test.txt", "w");
if (fp != NULL) {
    fprintf(fp, "Hello");
    fclose(fp);
}

#include <stdio.h>

int safe_open(const char *filename, const char *mode, FILE **fp) {
    *fp = fopen(filename, mode);
    if (*fp == NULL) {
        return 0;
    }
    return 1;
}

int main() {
    FILE *fp;
    if (safe_open("data.txt", "r", &fp)) {
        printf("文件打开成功\n");
        fclose(fp);
    } else {
        printf("文件打开失败\n");
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *fin = fopen("input.txt", "r");
    FILE *fout = fopen("output.txt", "w");
    if (fin == NULL || fout == NULL) {
        printf("文件打开失败\n");
        if (fin) fclose(fin);
        if (fout) fclose(fout);
        return 1;
    }
    int num, sum = 0;
    while (fscanf(fin, "%d", &num) == 1) {
        sum += num;
    }
    fprintf(fout, "%d\n", sum);
    fclose(fin);
    fclose(fout);
    return 0;
}
